3	const BASE_PRICE_BY_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	type Item = { type: string };
11	type Step = { op: "quote"; items: Item[] };
12	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
13	
14	const itemBasePrice = (item: Item): number => BASE_PRICE_BY_TYPE[item.type];
15	
16	const quotePremium = (step: Step): number =>
17	  step.items.reduce((sum, item) => sum + itemBasePrice(item), 0) + PROCESSING_FEE;
18	
19	export const runScenario = (input: unknown): unknown => {
20	  const scenario = input as Scenario;
21	  return {
22	    results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
23	  };
24	};
